import{c as a,a7 as i,y as r,B as t}from"./chunks/framework.BYQtDGaq.js";const h=JSON.parse('{"title":"ALBEF：对齐再融合的视觉语言预训练","description":"介绍 ALBEF 模型如何通过先对齐再融合的策略提升视觉语言表示学习效果","frontmatter":{"title":"ALBEF：对齐再融合的视觉语言预训练","description":"介绍 ALBEF 模型如何通过先对齐再融合的策略提升视觉语言表示学习效果"},"headers":[],"relativePath":"multimodal/vision-language/albef.md","filePath":"multimodal/vision-language/albef.md","lastUpdated":1782721961000}'),n={name:"multimodal/vision-language/albef.md"};function l(o,e,s,g,p,m){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="albef-对齐再融合的视觉语言预训练" tabindex="-1">ALBEF：对齐再融合的视觉语言预训练 <a class="header-anchor" href="#albef-对齐再融合的视觉语言预训练" aria-label="Permalink to “ALBEF：对齐再融合的视觉语言预训练”">​</a></h1><blockquote><p><strong>TL;DR</strong>：我们提出了一种新的视觉语言表示学习框架，该框架通过在融合之前首先对齐单模态表示来实现最先进的性能。</p></blockquote><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to “背景”">​</a></h2><p>视觉和语言是人类感知世界的两个最基本渠道。构建能够共同理解视觉数据（图像）和语言数据（文本）的智能机器，一直是人工智能领域的长期目标。视觉语言预训练（Vision-Language Pre-training，VLP）已成为解决这一问题的有效方法。然而，现有方法存在三个主要局限：</p><ul><li><strong>局限 1</strong>：以 CLIP 和 ALIGN 为代表的方法学习单模态图像编码器和文本编码器，在表示学习任务上取得了令人印象深刻的性能。但它们缺乏对图像和文本之间复杂交互进行建模的能力，因此不擅长需要细粒度图像-文本理解的任务。</li><li><strong>局限 2</strong>：以 UNITER 为代表的方法采用多模态编码器对图像和文本进行联合建模。然而，多模态 Transformer 的输入包含<strong>未对齐的</strong>基于区域的图像特征和单词 token 嵌入。由于视觉特征和文本特征驻留在各自的空间中，多模态编码器学习对它们的交互进行建模具有挑战性。此外，大多数方法使用预训练的目标检测器提取图像特征，这既昂贵又计算开销大。</li><li><strong>局限 3</strong>：用于预训练的数据集主要由从网络收集的<strong>噪声</strong>图像-文本对组成。广泛使用的预训练目标，例如掩码语言模型（MLM），很容易过拟合噪声文本，从而损害表示学习。</li></ul><p>为了解决这些局限，我们提出了 <strong>ALBEF（ALign BEfore Fuse）</strong>，一种新的视觉语言表示学习框架。ALBEF 在图像-文本检索、视觉问答（VQA）和自然语言视觉推理（NLVR）等多种视觉语言下游任务上实现了最先进的性能。</p><h2 id="将单模态表示与图像-文本对比学习结合" tabindex="-1">将单模态表示与图像-文本对比学习结合 <a class="header-anchor" href="#将单模态表示与图像-文本对比学习结合" aria-label="Permalink to “将单模态表示与图像-文本对比学习结合”">​</a></h2><p><img src="https://blog.salesforceairesearch.com/content/images/2021/06/Screenshot-2021-06-08-at-1.55.46-pm.png" alt="ALBEF 框架" title="ALBEF 框架"></p><p>如上图所示，ALBEF 包含图像编码器（ViT-B/16）、文本编码器（BERT 的前 6 层）和多模态编码器（BERT 的后 6 层，带有额外的交叉注意力层）。ALBEF 通过联合优化以下三个目标进行预训练：</p><ul><li><strong>目标 1：图像-文本对比学习（ITC）</strong> 应用于单模态图像编码器和文本编码器。它将图像特征和文本特征对齐，并训练单模态编码器以更好地理解图像和文本的语义。</li><li><strong>目标 2：图像-文本匹配（ITM）</strong> 应用于多模态编码器，预测一对图像和文本是正（匹配）还是负（不匹配）。我们提出了对比难负例挖掘（contrastive hard negative mining），选择具有更高对比相似性的信息丰富的负例。</li><li><strong>目标 3：掩码语言建模（MLM）</strong> 应用于多模态编码器。我们随机掩码文本 token，并训练模型使用图像和掩码文本来预测被掩码的 token。</li></ul><h2 id="从噪声图像-文本对中学习的动量蒸馏" tabindex="-1">从噪声图像-文本对中学习的动量蒸馏 <a class="header-anchor" href="#从噪声图像-文本对中学习的动量蒸馏" aria-label="Permalink to “从噪声图像-文本对中学习的动量蒸馏”">​</a></h2><p>从网络收集的图像-文本对通常是弱相关的：文本可能包含与图像无关的单词，或者图像可能包含文本中未描述的实体。为了从噪声数据中学习，我们提出了<strong>动量蒸馏（Momentum Distillation）</strong>，其中使用动量模型为图像-文本对比学习和掩码语言建模生成伪目标。</p><p>下图展示了图像的伪正文本示例，它产生了“年轻女子”和“树”等新概念。我们还从互信息最大化的角度提供了理论解释，表明动量蒸馏可以解释为为每个图像-文本对生成视图。</p><p><img src="https://blog.salesforceairesearch.com/content/images/2021/06/Screenshot-2021-06-08-at-1.58.48-pm.png" alt="图像的伪正文本" title="图像的伪正文本"></p><blockquote><p>图像的伪正文本示例。</p></blockquote><h2 id="总结与资源" tabindex="-1">总结与资源 <a class="header-anchor" href="#总结与资源" aria-label="Permalink to “总结与资源”">​</a></h2><p>ALBEF 是一个简单、端到端且功能强大的视觉语言表示学习框架。相关资源如下：</p><ul><li>论文：<a href="https://arxiv.org/abs/2107.07651" target="_blank" rel="noreferrer">Align before Fuse: Vision and Language Representation Learning with Momentum Distillation</a></li><li>代码与预训练模型：<a href="https://github.com/salesforce/ALBEF" target="_blank" rel="noreferrer">salesforce/ALBEF</a></li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to “参考”">​</a></h2><ol><li><em>Align before Fuse: Vision and Language Representation Learning with Momentum Distillation</em>. arXiv preprint arXiv:2107.07651, 2021.</li><li><em>Learning Transferable Visual Models from Natural Language Supervision</em>. arXiv preprint arXiv:2103.00020, 2021.</li><li><em>Scaling Up Visual and Vision-Language Representation Learning with Noisy Text Supervision</em>. arXiv preprint arXiv:2102.05918, 2021.</li><li><em>UNITER: Universal Image-Text Representation Learning</em>. ECCV, 2020.</li></ol>',20)])])}const d=a(n,[["render",l]]);export{h as __pageData,d as default};
